// ── UMAP scatter points ───────────────────────────────────────────────────────
const rng = (seed) => {
    let s = seed;
    return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646; };
};
const clusterCenters = [
    { cx: 2.1, cy: 1.8 }, // cluster 0 — nav/pilot
    { cx: -1.5, cy: -2.2 }, // cluster 1 — structural
    { cx: 3.2, cy: -1.4 }, // cluster 2 — helicopter
    { cx: -2.8, cy: 2.6 }, // cluster 3 — midair
];
const severities = ['Fatal', 'Fatal', 'Fatal', 'Severe', 'Moderate', 'Minor'];
const clusterColors = ['#8b5cf6', '#06b6d4', '#10b981', '#f59e0b'];
export const umapPoints = (() => {
    const rand = rng(42);
    const pts = [];
    const counts = [360, 4564, 121, 139];
    const samples = [80, 120, 60, 60];
    clusterCenters.forEach(({ cx, cy }, ci) => {
        for (let i = 0; i < samples[ci]; i++) {
            const r = rand() * 1.4;
            const theta = rand() * Math.PI * 2;
            pts.push({
                x: parseFloat((cx + r * Math.cos(theta)).toFixed(3)),
                y: parseFloat((cy + r * Math.sin(theta)).toFixed(3)),
                cluster: ci,
                severity: severities[Math.floor(rand() * severities.length)],
                color: clusterColors[ci],
            });
        }
    });
    return pts;
})();
